callGraph.callee:
notes
    .map((n) => {
      const title = n.title ? String(n.title).trim() : '';
      const body = String(n.body || '')
        .replace(/<[^>]+>/g, ' ')
        .replace(/\s+/g, ' ')
        .trim();
      if (title && body) return `${title} — ${body}`;
      return title || body;
    })
    .filter(Boolean)
    .join

